    /**
     */
    private fun _finalizeTrackGroups(onlyFirstGroup: Boolean = false): Boolean{
        var currentY: Double = 0.0
        var settings: com.omnifret.gplayer.Settings = this.layout.renderer.settings
        var smufl: com.omnifret.gplayer.EngravingSettings = settings.display.resources.engravingSettings
        var topBracketSpikeHeight: Double = smufl.glyphHeights.get(com.omnifret.gplayer.model.MusicFontSymbol.BracketTop)!!
        var bottomBracketSpikeHeight: Double = smufl.glyphHeights.get(com.omnifret.gplayer.model.MusicFontSymbol.BracketBottom)!!
        var previousStaff: com.omnifret.gplayer.rendering.staves.RenderStaff? = null
        var endSpikeOverflow: Double = 0.0
        var anyStaffVisible: Boolean = false
        for (group in this.staves)
        {
            var firstVisibleStaffInGroup: com.omnifret.gplayer.rendering.staves.RenderStaff? = null
            var lastVisibleStaffInGroup: com.omnifret.gplayer.rendering.staves.RenderStaff? = null
            for (staff in group.staves)
            {
                if (previousStaff != null && previousStaff!!.trackIndex != staff.trackIndex)
                {
                    currentY += settings.display.trackStaffPaddingBetween
                }
                var bracket: com.omnifret.gplayer.rendering.staves.SystemBracket? = if(this._staffToBracket.has(staff))  this._staffToBracket.get(staff) else null
                var hasBracket: Boolean? = com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bracket)) && !bracket!!.drawAsBrace) && bracket!!.canPaint
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(hasBracket)) && bracket!!.firstStaffInBracket == staff))
                {
                    var spikeOverflow: Double = topBracketSpikeHeight - staff.topOverflow
                    if (spikeOverflow > 0)
                    {
                        currentY += spikeOverflow
                    }
                }
                staff.x = this.accoladeWidth
                staff.y = currentY
                if (!onlyFirstGroup)
                {
                    staff.finalizeStaff()
                }
                if (staff.isVisible)
                {
                    currentY += staff.height
                    anyStaffVisible = true
                    previousStaff = staff
                    if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(firstVisibleStaffInGroup)))
                    {
