                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(hasBracket)) && bracket!!.lastStaffInBracket == staff))
                {
                    var spikeOverflow: Double = bottomBracketSpikeHeight - staff.bottomOverflow
                    if (spikeOverflow > 0)
                    {
                        if (staff.isVisible)
                        {
                            currentY += spikeOverflow
                        }
                        else 
                        {
                            endSpikeOverflow = spikeOverflow
                        }
                    }
                }
            }
            group.firstVisibleStaff = firstVisibleStaffInGroup
            group.lastVisibleStaff = lastVisibleStaffInGroup
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this.firstVisibleStaff)))
            {
                this.firstVisibleStaff = firstVisibleStaffInGroup
            }
            if (onlyFirstGroup)
            {
                break
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(endSpikeOverflow)))
        {
            currentY += endSpikeOverflow
        }
        this._contentHeight = currentY
        return anyStaffVisible
    }
    
    /**
     */
    public fun buildBoundingsLookup(cx: Double, cy: Double): Unit{
        var paramcy = cy
        if (this.layout.renderer.boundsLookup!!.isFinished)
        {
            return
        }
        var firstStaff: com.omnifret.gplayer.rendering.staves.RenderStaff = this.allStaves[(0).toInt()]
        var lastStaff: com.omnifret.gplayer.rendering.staves.RenderStaff = this.allStaves[(this.allStaves.length - (1.0).toDouble()).toInt()]
        paramcy += this.topPadding
        var visualTop: Double = paramcy + this.y + firstStaff.y
        var visualBottom: Double = paramcy + this.y + lastStaff.y + lastStaff.height
        var visualHeight: Double = visualBottom - visualTop
        var realTop: Double = paramcy + this.y
        var realBottom: Double = paramcy + this.y + this.height
        var realHeight: Double = realBottom - realTop
        var lineTop: Double = paramcy + this.y + firstStaff.y + firstStaff.topPadding + firstStaff.topOverflow
        var lineBottom: Double = paramcy + this.y + lastStaff.y + lastStaff.height - lastStaff.bottomPadding - lastStaff.bottomOverflow
        var lineHeight: Double = lineBottom - lineTop
        var x: Double = this.x + firstStaff.x
        var staffSystemBounds: com.omnifret.gplayer.rendering.utils.StaffSystemBounds = com.omnifret.gplayer.rendering.utils.StaffSystemBounds()
        staffSystemBounds.visualBounds = com.omnifret.gplayer.rendering.utils.Bounds()
        staffSystemBounds.visualBounds.x = cx + this.x
        staffSystemBounds.visualBounds.y = paramcy + this.y
        staffSystemBounds.visualBounds.w = this.width
        staffSystemBounds.visualBounds.h = this.height - this.topPadding - this.bottomPadding
        staffSystemBounds.realBounds = com.omnifret.gplayer.rendering.utils.Bounds()
        staffSystemBounds.realBounds.x = cx + this.x
        staffSystemBounds.realBounds.y = paramcy + this.y
        staffSystemBounds.realBounds.w = this.width
        staffSystemBounds.realBounds.h = this.height
        this.layout.renderer.boundsLookup!!.addStaffSystem(staffSystemBounds)
        var masterBarBoundsLookup: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.rendering.utils.MasterBarBounds> = com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.rendering.utils.MasterBarBounds>()
        if (true) {
            var i: Double = 0.0
            
            while(i < this.staves.length){
                for (staff in this.staves[(i).toInt()].staves)
                {
                    if (!staff.isVisible)
                    {
                        i++
                        continue
                    }
                    for (renderer in staff.barRenderers)
                    {
                        var masterBarBounds: com.omnifret.gplayer.rendering.utils.MasterBarBounds
                        if (!masterBarBoundsLookup.has(renderer.bar.masterBar.index))
                        {
                            masterBarBounds = com.omnifret.gplayer.rendering.utils.MasterBarBounds()
                            masterBarBounds.index = renderer.bar.masterBar.index
                            masterBarBounds.isFirstOfLine = renderer.isFirstOfStaff
                            masterBarBounds.realBounds = com.omnifret.gplayer.rendering.utils.Bounds()
                            masterBarBounds.realBounds.x = x + renderer.x
                            masterBarBounds.realBounds.y = realTop
                            masterBarBounds.realBounds.w = renderer.width
                            masterBarBounds.realBounds.h = realHeight
                            masterBarBounds.visualBounds = com.omnifret.gplayer.rendering.utils.Bounds()
                            masterBarBounds.visualBounds.x = x + renderer.x
                            masterBarBounds.visualBounds.y = visualTop
                            masterBarBounds.visualBounds.w = renderer.width
                            masterBarBounds.visualBounds.h = visualHeight
                            masterBarBounds.lineAlignedBounds = com.omnifret.gplayer.rendering.utils.Bounds()
                            masterBarBounds.lineAlignedBounds.x = x + renderer.x
                            masterBarBounds.lineAlignedBounds.y = lineTop
                            masterBarBounds.lineAlignedBounds.w = renderer.width
                            masterBarBounds.lineAlignedBounds.h = lineHeight
                            this.layout.renderer.boundsLookup!!.addMasterBar(masterBarBounds)
                            masterBarBoundsLookup.set(masterBarBounds.index, masterBarBounds)
                        }
                        else 
                        {
                            masterBarBounds = masterBarBoundsLookup.get(renderer.bar.masterBar.index)!!
                        }
                        renderer.buildBoundingsLookup(masterBarBounds, x, paramcy + this.y + staff.y)
                    }
