        }
    }
    
    /**
     */
    public fun getBarX(index: Double): Double{
        if (this.allStaves.length == 0.0 || this.layout.renderer.tracks!!.length == 0.0)
        {
            return 0.0
        }
        var bar: com.omnifret.gplayer.model.Bar = this.layout.renderer.tracks!![(0).toInt()].staves[(0).toInt()].bars[(index).toInt()]
        var renderer: com.omnifret.gplayer.rendering.BarRendererBase = this.layout.getRendererForBar(this.allStaves[(0).toInt()].staffId, bar)!!
        return renderer.x
    }
    
