        }
        var bravuraBraceHeightAtMusicFontSize: Double = smuflMetrics.glyphHeights.get(com.omnifret.gplayer.model.MusicFontSymbol.Brace)!!
        var bravuraBraceWidthAtMusicFontSize: Double = smuflMetrics.glyphWidths.get(com.omnifret.gplayer.model.MusicFontSymbol.Brace)!!
        if (this.drawAsBrace)
        {
            this.width = bravuraBraceWidthAtMusicFontSize
        }
        else 
        {
            this.width = smuflMetrics.bracketThickness
        }
        if (!this.drawAsBrace)
        {
            return
        }
        var firstStart: Double = this.firstVisibleStaffInBracket!!.contentTop
        var lastEnd: Double = this.lastVisibleStaffInBracket!!.contentBottom
        var requiredHeight: Double = lastEnd - firstStart
        var requiredScaleForBracket: Double = requiredHeight / bravuraBraceHeightAtMusicFontSize
        this.braceScale = requiredScaleForBracket
        this.width = bravuraBraceWidthAtMusicFontSize * this.braceScale
    }
    
}

@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal open class SingleTrackSystemBracket: com.omnifret.gplayer.rendering.staves.SystemBracket
{
    protected var track: com.omnifret.gplayer.model.Track
    
    public constructor(system: com.omnifret.gplayer.rendering.staves.StaffSystem, track: com.omnifret.gplayer.model.Track)
        : super(system){
        this.track = track
        this.drawAsBrace = com.omnifret.gplayer.rendering.staves.SingleTrackSystemBracket.isTrackDrawAsBrace(track)
    }
    
    /**
     */
    public override fun includesStaff(r: com.omnifret.gplayer.rendering.staves.RenderStaff): Boolean{
        return r.modelStaff.track == this.track
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        public fun isTrackDrawAsBrace(track: com.omnifret.gplayer.model.Track): Boolean{
            return track.staves.filter(fun(s: com.omnifret.gplayer.model.Staff): Boolean{
                return (s.showStandardNotation as Boolean)
            }
            ).length > 1
        }
        
    }
}

@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal class SimilarInstrumentSystemBracket: com.omnifret.gplayer.rendering.staves.SingleTrackSystemBracket
{
    /**
     */
    public override fun includesStaff(r: com.omnifret.gplayer.rendering.staves.RenderStaff): Boolean{
        if (r.modelStaff.track == this.track)
        {
            return true
        }
        if (this.drawAsBrace)
        {
            return false
        }
        return this.track.playbackInfo.program == r.modelStaff.track.playbackInfo.program
    }
    
    public constructor(system: com.omnifret.gplayer.rendering.staves.StaffSystem, track: com.omnifret.gplayer.model.Track)
        : super(system, track)
}

